import { NextResponse } from "next/server";
import fs from "fs";
import path from "path";

export async function POST() {
  try {
    const today = new Date().toISOString().split("T")[0];
    
    // 로컬 backend 폴더의 경로 설정 (상위 폴더에 있는 backend)
    const backendDir = path.join(process.cwd(), "..", "backend");
    const filePath = path.join(backendDir, "traffic_log.json");
    
    let trafficData: Record<string, number> = {};
    
    // backend 폴더가 존재할 경우 파일에 직접 쓰기 수행 (로컬 개발 환경 전용)
    if (fs.existsSync(backendDir)) {
      if (fs.existsSync(filePath)) {
        try {
          const raw = fs.readFileSync(filePath, "utf8");
          trafficData = JSON.parse(raw);
        } catch (e) {
          trafficData = {};
        }
      }
      
      if (!trafficData[today]) {
        trafficData[today] = 0;
      }
      trafficData[today] += 1;
      
      fs.writeFileSync(filePath, JSON.stringify(trafficData, null, 4), "utf8");
      console.log(`[Local Traffic Track] Visit count for today (${today}): ${trafficData[today]}`);
    } else {
      console.log(`[Mock Traffic Track] Visit counted for today (${today}) - Sandbox/Cloud Mode`);
    }
    
    return NextResponse.json({ status: "success", today_visits: trafficData[today] || 1 });
  } catch (error: any) {
    console.error("Traffic track visit error:", error);
    // 프로덕션이나 배포 환경에서 파일 시스템이 락에 걸리거나 오류가 나도 무결하게 처리
    return NextResponse.json({ status: "success", error: error.message });
  }
}
